"const { createClient } = require('@supabase/supabase-js');
const fs = require('fs');

const envContent = fs.readFileSync('.env.local', 'utf-8');
const env = {};
envContent.split('\n').forEach(line => {
  const parts = line.split('=');
  if (parts.length >= 2) {
    const key = parts[0].trim();
    const val = parts.slice(1).join('=').trim();
    env[key] = val;
  }
});

const supabaseUrl = env['NEXT_PUBLIC_SUPABASE_URL'];
const supabaseAnonKey = env['NEXT_PUBLIC_SUPABASE_PUBLISHABLE_KEY'];

if (!supabaseUrl || !supabaseAnonKey) {
  console.error('Env variables missing');
  process.exit(1);
}

const supabase = createClient(supabaseUrl, supabaseAnonKey);

async function run() {
  const { data, error } = await supabase
    .from('website_pooja_products')
    .select('id, name, testimonials, ui_labels');

  if (error) {
    console.error('Error fetching table:', error);
  } else if (data) {
    data.forEach(item => {
      console.log(`Product: ${item.name} (${item.id})`);
      console.log('Testimonials:', JSON.stringify(item.testimonials, null, 2));
      console.log('UI Labels:', JSON.stringify(item.ui_labels, null, 2));
      console.log('----------------------------------------');
    });
  }
}

run();
"
